import{_ as i,o as e,c as s,ae as l}from"./chunks/framework.jfJLTIcL.js";const k=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/quick-start.md","filePath":"zh-CN/quick-start.md","lastUpdated":1776859840000}'),t={name:"zh-CN/quick-start.md"};function o(p,a,n,d,h,r){return e(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><h2 id="_1-安装依赖" tabindex="-1">1. 安装依赖 <a class="header-anchor" href="#_1-安装依赖" aria-label="Permalink to &quot;1. 安装依赖&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm install</span></span></code></pre></div><p>VILab 现在已经支持同一仓库下的 Windows 和 Apple Silicon macOS 桌面开发。</p><h2 id="_2-启动桌面-app" tabindex="-1">2. 启动桌面 App <a class="header-anchor" href="#_2-启动桌面-app" aria-label="Permalink to &quot;2. 启动桌面 App&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm run dev</span></span></code></pre></div><p>在 Apple Silicon macOS 上，也可以直接使用辅助脚本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/dev-mac.sh</span></span></code></pre></div><p>如果你在 Windows 上编译本地 Whisper 运行时，可能还需要一个可用的 64-bit <code>libclang.dll</code>。仓库里的 <code>npm run dev</code>、<code>npm run build</code>、<code>npm run cargo:check</code> 会优先自动探测常见安装路径。如果 <code>cargo</code> 仍然在 <code>whisper-rs-sys</code> 阶段失败，再把 <code>LIBCLANG_PATH</code> 指向包含该 DLL 的目录，然后重新执行命令。</p><p>同一条启动链路现在也会自动为内置 SenseVoice 准备 ONNX Runtime。通常不需要再手动安装 <code>onnxruntime.dll</code>。</p><p>在 macOS 上，第一次完整使用听写流程时，还需要给系统授权：</p><ul><li>麦克风权限，用于录音</li><li>辅助功能权限，用于全局快捷键和把结果写回当前前台应用</li></ul><p>当前 macOS 默认听写快捷键是 <code>Cmd+Shift+Option+D</code>。</p><p>这个命令会启动：</p><ul><li>Vite 前端</li><li>Tauri 桌面壳</li><li>由 App 管理的 VILab 内嵌 HTTP 服务</li></ul><h2 id="_3-确认服务地址" tabindex="-1">3. 确认服务地址 <a class="header-anchor" href="#_3-确认服务地址" aria-label="Permalink to &quot;3. 确认服务地址&quot;">​</a></h2><p>打开桌面 App 的 <strong>设置</strong>，检查 <strong>Server URL</strong>。</p><p>当前默认值是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://127.0.0.1:9876</span></span></code></pre></div><h2 id="_4-检查健康状态" tabindex="-1">4. 检查健康状态 <a class="header-anchor" href="#_4-检查健康状态" aria-label="Permalink to &quot;4. 检查健康状态&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl http:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">127.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9876</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">health</span></span></code></pre></div><p>预期返回：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;serviceId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;uuid&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.2.1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;publicModel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;vilab-local-stt&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>publicModel</code> 表示当前对外暴露的 STT 模型别名。它既可能对应当前激活的本地模型，也可能对应当前路由到的云端 STT 别名。</p><h2 id="_5-先选择-stt-模式" tabindex="-1">5. 先选择 STT 模式 <a class="header-anchor" href="#_5-先选择-stt-模式" aria-label="Permalink to &quot;5. 先选择 STT 模式&quot;">​</a></h2><p>打开 <strong>设置</strong>，在 <strong>Routing and models -&gt; STT mode</strong> 中选择：</p><ul><li><code>Local</code>：桌面录音和 <code>/v1/audio/transcriptions</code> 都走当前激活的本地语音运行时</li><li><code>Cloud</code>：桌面录音和 <code>/v1/audio/transcriptions</code> 都走当前选择的云端 Provider 和云端 STT 模型</li></ul><p>首页快速开始区域现在会直接显示当前 STT 来源和模型名，例如：</p><ul><li><code>本地 路 Whisper Small</code></li><li><code>本地 路 SenseVoice</code></li><li><code>云端 路 whisper-large-v3-turbo</code></li></ul><p>设置现在会在每次调整后自动保存。切换 STT 模式、听写优先级、Provider 或本地模型后，不需要再额外点击保存按钮。</p><h2 id="_6-如果使用本地-stt-再安装并激活本地语音模型" tabindex="-1">6. 如果使用本地 STT，再安装并激活本地语音模型 <a class="header-anchor" href="#_6-如果使用本地-stt-再安装并激活本地语音模型" aria-label="Permalink to &quot;6. 如果使用本地 STT，再安装并激活本地语音模型&quot;">​</a></h2><p>在桌面录音或局域网客户端调用 <code>/v1/audio/transcriptions</code> 之前，先在 <strong>设置</strong> 的 <strong>Local speech models</strong> 区域完成以下任一方式：</p><ul><li>下载内置模型，例如 <code>Whisper Base</code>、<code>Whisper Small</code> 或 <code>SenseVoice</code></li><li>或者把兼容的 Whisper.cpp <code>.bin</code> 模型放进 models 目录后点击刷新</li><li>激活你要给当前宿主使用的模型</li></ul><p>桌面 App 和内嵌 HTTP 服务现在共用同一套本地语音转录运行时。</p><p>内置 SenseVoice 会以受管目录模型的形式安装。当前阶段，手动放入的自定义本地模型仍然只支持 Whisper.cpp <code>.bin</code> 文件。</p><p>本次版本里的内置 SenseVoice 同时支持 Windows 和 Apple Silicon macOS。</p><p>如果你切到 <code>Cloud</code> 模式，则在同一个 routing 区域里配置云端 STT provider 和云端 STT model。</p><h2 id="_7-选择转录输出模式" tabindex="-1">7. 选择转录输出模式 <a class="header-anchor" href="#_7-选择转录输出模式" aria-label="Permalink to &quot;7. 选择转录输出模式&quot;">​</a></h2><p>打开 <strong>设置</strong>，配置 <strong>Transcript mode</strong> 和 <strong>Scene mode</strong>：</p><ul><li><code>Verbatim</code>：尽量保持和原始转录接近</li><li><code>Smart Clean</code>：只用本地规则清理口头语、重复词和明显改口</li><li><code>Polished</code>：在 smart clean 之后调用云端文本变换，并可按 <code>chat</code>、<code>email</code>、<code>notes</code> 场景整理</li></ul><p>历史记录现在会为每条 session 保留多个输出变体，因此你可以在 raw、smart clean、polished 之间切换，而不会丢失原始转录。</p><h2 id="_8-配置文本变换-provider" tabindex="-1">8. 配置文本变换 Provider <a class="header-anchor" href="#_8-配置文本变换-provider" aria-label="Permalink to &quot;8. 配置文本变换 Provider&quot;">​</a></h2><p>云端 Provider 现在主要负责 polished 听写、清理、改写、翻译等文本后处理能力。</p><p>在 <strong>设置</strong> 中配置：</p><ul><li>Transform provider</li><li>API key</li><li>API base URL</li><li>Rewrite model</li></ul><h2 id="_9-打开测试平台" tabindex="-1">9. 打开测试平台 <a class="header-anchor" href="#_9-打开测试平台" aria-label="Permalink to &quot;9. 打开测试平台&quot;">​</a></h2><p>在侧边栏底部文档入口下面点击 <strong>测试平台</strong>，会在浏览器中打开 Prompt Lab。</p><p>测试平台用于内部 prompt / model 对比：</p><ul><li><code>Smart Clean</code> 只跑本地规则，通常会非常快</li><li><code>Polished</code> 才会真正调用所选 Provider、模型、Preset 和可选 Prompt Override</li><li>所有实验结果都不会写入正式历史记录</li></ul><h2 id="_10-创建-external-api-key" tabindex="-1">10. 创建 external API key <a class="header-anchor" href="#_10-创建-external-api-key" aria-label="Permalink to &quot;10. 创建 external API key&quot;">​</a></h2><p>在 <strong>设置 -&gt; External API keys</strong> 中：</p><ul><li>按项目、脚本、设备或集成分别创建 key</li><li>不要把 <code>adminKey</code> 发给普通调用方</li><li>新 key 生成后立刻复制，完整值只会显示一次</li></ul><h2 id="_11-打包-macos-app" tabindex="-1">11. 打包 macOS App <a class="header-anchor" href="#_11-打包-macos-app" aria-label="Permalink to &quot;11. 打包 macOS App&quot;">​</a></h2><p>在 Apple Silicon macOS 上：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:mac</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/run-mac-app.sh</span></span></code></pre></div><p><code>npm run build:mac</code> 会生成 <code>.app</code> 和 <code>.dmg</code>，<code>run-mac-app.sh</code> 会直接打开最新打好的本地安装包，方便做快速冒烟验证。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/zh-CN/lan-deployment">局域网部署</a></li><li><a href="/docs/zh-CN/api-keys">API Key 指南</a></li><li><a href="/docs/zh-CN/integrations">集成示例</a></li></ul>`,58)])])}const u=i(t,[["render",o]]);export{k as __pageData,u as default};
